+func TestWithFallback_FillsEmpty(t *testing.T) {
+	// Create an IconSet with some empty fields
+	partial := IconSet{
+		Check: "Y",
+		Cross: "N",
+		// Everything else is empty
+	}
+	out := partial.WithFallback(ASCII)
+	if out.Check != "Y" {
